import requests

def get_gwar_discography():
    url = "https://api.example.com/gwar/discography"
    response = requests.get(url)
    if response.status_code == 200:
        return response.json()  # Returns a list of albums with metadata
    else:
        return None

# Example usage:
discography = get_gwar_discography()
for album in discography:
    print(f"{album['title']} ({album['year']}) - {album['type']}")
